void TFT_SEND_CMD(unsigned char o_command)
{
	GPIO_ResetBits(SPI_DC);
    GPIO_ResetBits(SPI_CS);
    SPI1_WriteByte(o_command);
    GPIO_SetBits(SPI_CS);
}
  

void TFT_SEND_DATA(unsigned char o_data)
{ 
    GPIO_SetBits(SPI_DC);
    GPIO_ResetBits(SPI_CS);
    SPI1_WriteByte(o_data);
    GPIO_SetBits(SPI_CS);
}

void set_window(unsigned int x, unsigned int y, unsigned int width, unsigned int high)
{
	TFT_SEND_CMD(0x2a); 		//Column address set
	TFT_SEND_DATA(x >> 8); 		//start column
	TFT_SEND_DATA(x);
	x = x + width - 1;
	TFT_SEND_DATA(x >> 8);		//end column
	TFT_SEND_DATA(x);

	TFT_SEND_CMD(0x2b); 		//Row address set
	TFT_SEND_DATA(y >> 8); 		//start row
	TFT_SEND_DATA(y); 
	y = y + high - 1;
	TFT_SEND_DATA(y >> 8);		//end row
	TFT_SEND_DATA(y);
	
	TFT_SEND_CMD(0x2C);			//Memory write
}

void OLED_clear(void)
{
	uint32_t i = 0;
	uint16_t y = 0;
	uint8_t clean_Buffer[320 * 3];
    for(i = 0; i < 960; i ++) 
        clean_Buffer[i]   = 0x00;   

	set_window(0, 0, 360, 240);
	
    GPIO_SetBits(SPI_DC);   // DC=1
    GPIO_ResetBits(SPI_CS); // CS=0

    for(y = 0; y < 240; y++) {
        DMA_StartLineTransfer(clean_Buffer, 960);
    }

    GPIO_SetBits(SPI_CS);   // CS=1
	GPIO_ResetBits(SPI_DC);
}


//但实际，应该用更完整的结构体，可以去用window_clear的地方找需求
//实际情况是算都算出来了，打算直接传值算了
void window_clear(int x, int y, int width, int high)
{
	uint32_t i = 0;
	uint32_t sum_data = width * 3;
	uint8_t clean_Buffer1[960];
	
	set_window(x, y, sum_data, high);
	for(i = 0; i < sum_data; i++) 
			clean_Buffer1[i]   = 0x00;   
	
	GPIO_SetBits(SPI_DC);   // DC=1
	GPIO_ResetBits(SPI_CS); // CS=0
	
	for(i = 0; i < high; i++) 
		DMA_StartLineTransfer(clean_Buffer1, sum_data);
    
    GPIO_SetBits(SPI_CS);   // CS=1
}

void window_set(Window_Def *Window_Struct)
{
	TFT_SEND_CMD(0x2a); 		//Column address set
	TFT_SEND_DATA(Window_Struct->window_x >> 8); 		//start column
	TFT_SEND_DATA(Window_Struct->window_x);
	Window_Struct->window_x = Window_Struct->window_x + Window_Struct->width - 1;
	TFT_SEND_DATA(Window_Struct->window_x >> 8);		//end column
	TFT_SEND_DATA(Window_Struct->window_x);

	TFT_SEND_CMD(0x2b); 		//Row address set
	TFT_SEND_DATA(Window_Struct->window_y >> 8); 		//start row
	TFT_SEND_DATA(Window_Struct->window_y); 
	Window_Struct->window_y = Window_Struct->window_y + Window_Struct->high - 1;
	TFT_SEND_DATA(Window_Struct->window_y >> 8);		//end row
	TFT_SEND_DATA(Window_Struct->window_y);
	
	TFT_SEND_CMD(0x2C);			//Memory write
}

void Display_Image_start(void)
{
	set_window(69, 69, 100, 100);
	DMA_Trans(picture_tab0,30000);	
}
	
void DMA_Trans(const unsigned char *point, unsigned int pixel_num)
{
	GPIO_SetBits(SPI_DC);   // DC = 1 (数据)
    GPIO_ResetBits(SPI_CS); // CS = 0 (选中)
	
    //DMA_StartLineTransfer 函数是阻塞的，直接调用
	//注意pixel_num是实际像素数*3（因为是GBR888）
    DMA_StartLineTransfer(point, pixel_num);

    GPIO_SetBits(SPI_CS);   // CS = 1(传输完成，拉高 CS)
}


void OLED_init(void)				////ST7789V2
{
	//GPIO_ResetBits(SPI_SCK);
	GPIO_ResetBits(SPI_RST);
	Delay_ms(1000);
	
	GPIO_SetBits(SPI_RST);
	Delay_ms(1000);
	  
    TFT_SEND_CMD(0x11); 			//Sleep Out
	Delay_ms(120);               //DELAY120ms 
	  
	//--------------------------------ST7789S Frame rate setting----------------------------------// 
	TFT_SEND_CMD(0x2a); 		//Column address set
	TFT_SEND_DATA(0x00); 		//start column
	TFT_SEND_DATA(0x00); 
	TFT_SEND_DATA(0x00);		//end column
	TFT_SEND_DATA(0xef);

	TFT_SEND_CMD(0x2b); 		//Row address set
	TFT_SEND_DATA(0x00); 		//start row
	TFT_SEND_DATA(0x00); 
	TFT_SEND_DATA(0x01);		//end row
	TFT_SEND_DATA(0x3f);

	TFT_SEND_CMD(0xb2); 		//Porch control
	TFT_SEND_DATA(0x0c); 
	TFT_SEND_DATA(0x0c); 
	TFT_SEND_DATA(0x00); 
	TFT_SEND_DATA(0x33); 
	TFT_SEND_DATA(0x33); 

	TFT_SEND_CMD(0x20); 		//Display Inversion Off

	TFT_SEND_CMD(0xb7); 		//Gate control
	TFT_SEND_DATA(0x56);   		//35
//---------------------------------ST7789S Power setting--------------------------------------// 
	TFT_SEND_CMD(0xbb); //VCOMS Setting
	TFT_SEND_DATA(0x18);  //1f

	TFT_SEND_CMD(0xc0); 		//LCM Control
	TFT_SEND_DATA(0x2c); 

	TFT_SEND_CMD(0xc2); 		//VDV and VRH Command Enable
	TFT_SEND_DATA(0x01); 

	TFT_SEND_CMD(0xc3); //VRH Set
	TFT_SEND_DATA(0x1f); //12

	TFT_SEND_CMD(0xc4); 			//VDV Setting
	TFT_SEND_DATA(0x20); 

	TFT_SEND_CMD(0xc6); 			//FR Control 2
	TFT_SEND_DATA(0x0f); 

	TFT_SEND_CMD(0xd0);  //Power Control 1
	TFT_SEND_DATA(0xa6);   //a4
	TFT_SEND_DATA(0xa1); 
//--------------------------------ST7789S gamma setting---------------------------------------// 

	TFT_SEND_CMD(0xe0); 
	TFT_SEND_DATA(0xd0); 
	TFT_SEND_DATA(0x0d); 
	TFT_SEND_DATA(0x14); 
	TFT_SEND_DATA(0x0b); 
	TFT_SEND_DATA(0x0b); 
	TFT_SEND_DATA(0x07); 
	TFT_SEND_DATA(0x3a);  
	TFT_SEND_DATA(0x44); 
	TFT_SEND_DATA(0x50); 
	TFT_SEND_DATA(0x08); 
	TFT_SEND_DATA(0x13); 
	TFT_SEND_DATA(0x13); 
	TFT_SEND_DATA(0x2d); 
	TFT_SEND_DATA(0x32); 

	TFT_SEND_CMD(0xe1); 				//Negative Voltage Gamma Contro
	TFT_SEND_DATA(0xd0); 
	TFT_SEND_DATA(0x0d); 
	TFT_SEND_DATA(0x14); 
	TFT_SEND_DATA(0x0b); 
	TFT_SEND_DATA(0x0b); 
	TFT_SEND_DATA(0x07); 
	TFT_SEND_DATA(0x3a); 
	TFT_SEND_DATA(0x44); 
	TFT_SEND_DATA(0x50); 
	TFT_SEND_DATA(0x08); 
	TFT_SEND_DATA(0x13); 
	TFT_SEND_DATA(0x13); 
	TFT_SEND_DATA(0x2d); 
	TFT_SEND_DATA(0x32);
	
	TFT_SEND_CMD(0x36); 			//Memory data access control
	TFT_SEND_DATA(0x68); 
	
	TFT_SEND_CMD(0x3A); 			//Interface pixel format
	TFT_SEND_DATA(0x66);			//262K  RGB 6 6 6

	TFT_SEND_CMD(0xe7); 			//SPI2 enable    ƴӃ2ʽ¾ݍ¨µÀģʽ
	TFT_SEND_DATA(0x00); 


	TFT_SEND_CMD(0x21);			//Display inversion on
	TFT_SEND_CMD(0x29); 			//Display on
	
	TFT_SEND_CMD(0x2C);			//Memory write
	
	
	OLED_clear();
	Delay_ms(50);
	
	page_Start();
	GPIO_SetBits(SPI_BL);
	
}



void Test_Polling_Red(void)
{
	uint32_t i = 0;
    TFT_SEND_CMD(0x2B);
    TFT_SEND_DATA(0x00); TFT_SEND_DATA(0x00);
    TFT_SEND_DATA(0x00); TFT_SEND_DATA(0xEF);
    TFT_SEND_CMD(0x2A);
    TFT_SEND_DATA(0x00); TFT_SEND_DATA(00);
    TFT_SEND_DATA(0x01); TFT_SEND_DATA(0x3F);
    TFT_SEND_CMD(0x2C);

    for(i = 0; i < 240 * 320; i++) {
        TFT_SEND_DATA(0xFF);  // R
        TFT_SEND_DATA(0x00);  // G
        TFT_SEND_DATA(0x00);  // B
    }
}
